  if (b == 0) return a;

  return gcd(b, a % b);

}



ll extgcd(ll a, ll b, ll& x, ll& y) {

  if (b == 0) {

    x = 1, y = 0; return a;

  }

  ll q = a/b, g = extgcd(b, a - q*b, x, y);

  ll z = x - q * y;

  x = y;

  y = z;

  return g;

}



ll invmod (ll a, ll m) { // a^-1 mod m

  ll x, y;

  extgcd(a, m, x, y);

  x %= m;

  if (x < 0) x += m;

  return x;

}



ll *fac, *finv, *inv;



void nCk_init(ll mod) {

  fac = new ll[NCK_MAX];

  finv = new ll[NCK_MAX];

  inv = new ll[NCK_MAX];

  fac[0] = fac[1] = 1;

  finv[0] = finv[1] = 1;

  inv[1] = 1;

  for (ll i = 2; i < NCK_MAX; i++) {

    fac[i] = fac[i-1] * i % mod;

    inv[i] = mod - inv[mod%i] * (mod / i) % mod;

    finv[i] = finv[i-1] * inv[i] % mod;

  }

}



ll nCk(ll n, ll k, ll mod) {

  if (fac == NULL) nCk_init(mod);

  if (n < k) return 0;

  if (n < 0 || k < 0) return 0;

  return fac[n] * (finv[k] * finv[n-k] % mod) % mod;

}



